import std.dict
import std.vector

func solve(points: Array<Array<Int64>>): Int64 {
    let mod_val: Int64 = 1000000007
    let counts = dict()
    for point in points {
        let y_val = point[1]
        if counts.has_key(y_val) {
            counts.set(y_val, counts.get(y_val) + 1)
        } else {
            counts.set(y_val, 1)
        }
    }
    let value_list = vector<Int64>()
    let keys = counts.keys()
    for key in keys {
        let cnt = counts.get(key)
        if cnt >= 2 {
            let v = (cnt * (cnt - 1)) // 2
            value_list.push_back(v)
        }
    }
    let total: Int64 = 0
    let s: Int64 = 0
    for i in range(0, value_list.size()) {
        let v = value_list[i]
        total = (total + s * v) % mod_val
        s = (s + v) % mod_val
    }
    return total
}
```

