const MOD: i64 = 1000000007;
const INV2: i64 = 500000004;

pub fn solve(points: Vec<Vec<i64>>) -> i64 {
    let mut groups: HashMap<i64, i64> = HashMap::new();
    for point in points.iter() {
        let y = point[1];
        *groups.entry(y).or_insert(0) += 1;
    }

    let mut s1: i64 = 0;
    let mut s2: i64 = 0;
    for (_, &cnt) in groups.iter() {
        if cnt < 2 {
            continue;
        }
        let n = cnt;
        let v = n * (n - 1) / 2;
        let v_mod = v % MOD;
        s1 = (s1 + v_mod) % MOD;
        s2 = (s2 + (v_mod * v_mod) % MOD) % MOD;
    }

    let mut total = (s1 * s1) % MOD;
    total = (total - s2) % MOD;
    if total < 0 {
        total += MOD;
    }
    total = (total * INV2) % MOD;
    total
}
